import { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Booking() {
  const [bookings, setBookings] = useState([]);
  const [userName, setUserName] = useState("");
  const [serviceName, setServiceName] = useState("");

  const navigate = useNavigate();

  const fetchBookings = () => {
    const token = localStorage.getItem("token");

    axios
      .get("http://localhost:5000/api/bookings", {
        headers: {
          Authorization: `Bearer ${token}`
        }
      })
      .then(res => setBookings(res.data))
      .catch(err => console.log(err));
  };

  useEffect(() => {
    const token = localStorage.getItem("token");

    if (!token) {
      navigate("/login");
      return;
    }

    fetchBookings();
  }, [navigate]);

  const bookService = () => {
    const token = localStorage.getItem("token");

    axios
      .post(
        "http://localhost:5000/api/bookings",
        {
          userName,
          serviceName
        },
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      )
      .then(() => {
        alert("Booked!");
        fetchBookings();
      })
      .catch(err => console.log(err));
  };

  const logout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  return (
  <div style={styles.page}>
    <div style={styles.topBar}>
      <h2>Booking Dashboard</h2>
      <button onClick={logout}>Logout</button>
    </div>

    <div style={styles.form}>
      <input placeholder="Your Name" onChange={(e) => setUserName(e.target.value)} />
      <input placeholder="Service Name" onChange={(e) => setServiceName(e.target.value)} />
      <button onClick={bookService}>Book Service</button>
    </div>

    <div style={styles.list}>
      <h3>Your Bookings</h3>

      {bookings.map((b, i) => (
        <div key={i} style={styles.card}>
          {b.userName} → {b.serviceName}
        </div>
      ))}
    </div>
  </div>
  );
}

export default Booking;
